# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.DependencyInjection;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();

var app = builder.Build();

app.UseHttpsRedirection();
app.UseStaticFiles();
app.UseAuthorization();
app.MapControllers();

app.Run();

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private static readonly Dictionary<string, List<string>> AllowedFileTypes = new()
    {
        { "avatar", new List<string> { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" } },
        { "document", new List<string> { ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx", ".txt", ".csv" } }
    };

    private const long MaxAvatarSize = 5 * 1024 * 1024;
    private const long MaxDocumentSize = 50 * 1024 * 1024;

    [HttpPost("avatar")]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        return await UploadFile(file, "avatar", MaxAvatarSize);
    }

    [HttpPost("document")]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        return await UploadFile(file, "document", MaxDocumentSize);
    }

    private async Task<IActionResult> UploadFile(IFormFile file, string fileType, long maxSize)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new { error = "No file uploaded" });
        }

        if (file.Length > maxSize)
        {
            return BadRequest(new { error = $"File size exceeds maximum allowed size of {maxSize / (1024 * 1024)} MB" });
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (!AllowedFileTypes.ContainsKey(fileType) || !AllowedFileTypes[fileType].Contains(extension))
        {
            return BadRequest(new { error = $"File type {extension} is not allowed for {fileType}" });
        }

        try
        {
            var uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads", fileType);
            
            if (!Directory.Exists(uploadsFolder))
            {
                Directory.CreateDirectory(uploadsFolder);
            }

            var uniqueFileName = $"{Guid.NewGuid()}{extension}";
            var filePath = Path.Combine(uploadsFolder, uniqueFileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = $"/uploads/{fileType}/{uniqueFileName}";

            return Ok(new
            {
                success = true,
                fileName = uniqueFileName,
                originalFileName = file.FileName,
                filePath = relativePath,
                fileSize = file.Length,
                fileType = extension,
                uploadedAt = DateTime.UtcNow
            });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = "Error uploading file", details = ex.Message });
        }
    }

    [HttpPost("batch")]
    public async Task<IActionResult> UploadMultipleFiles([FromForm] BatchUploadRequest request)
    {
        if (request.Files == null || !request.Files.Any())
        {
            return BadRequest(new { error = "No files uploaded" });
        }

        var results = new List<object>();
        var fileType = request.FileType ?? "document";
        var maxSize = fileType == "avatar" ? MaxAvatarSize : MaxDocumentSize;

        foreach (var file in request.Files)
        {
            if (file.Length == 0)
            {
                results.Add(new { fileName = file.FileName, success = false, error = "Empty file" });
                continue;
            }

            if (file.Length > maxSize)
            {
                results.Add(new { fileName = file.FileName, success = false, error = "File too large" });
                continue;
            }

            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

            if (!AllowedFileTypes.ContainsKey(fileType) || !AllowedFileTypes[fileType].Contains(extension))
            {
                results.Add(new { fileName = file.FileName, success = false, error = "Invalid file type" });
                continue;
            }

            try
            {
                var uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads", fileType);
                
                if (!Directory.Exists(uploadsFolder))
                {
                    Directory.CreateDirectory(uploadsFolder);
                }

                var uniqueFileName = $"{Guid.NewGuid()}{extension}";
                var filePath = Path.Combine(uploadsFolder, uniqueFileName);

                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    await file.CopyToAsync(stream);
                }

                var relativePath = $"/uploads/{fileType}/{uniqueFileName}";

                results.Add(new
                {
                    success = true,
                    fileName = uniqueFileName,
                    originalFileName = file.FileName,
                    filePath = relativePath,
                    fileSize = file.Length,
                    fileType = extension
                });
            }
            catch (Exception ex)
            {
                results.Add(new { fileName = file.FileName, success = false, error = ex.Message });
            }
        }

        return Ok(new
        {
            totalFiles = request.Files.Count,
            successfulUploads = results.Count(r => ((dynamic)r).success == true),
            results
        });
    }

    [HttpDelete("{fileType}/{fileName}")]
    public IActionResult DeleteFile(string fileType, string fileName)
    {
        if (!AllowedFileTypes.ContainsKey(fileType))
        {
            return BadRequest(new { error = "Invalid file type" });
        }

        try
        {
            var filePath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads", fileType, fileName);

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound(new { error = "File not found" });
            }

            System.IO.File.Delete(filePath);

            return Ok(new { success = true, message = "File deleted successfully" });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = "Error deleting file", details = ex.Message });
        }
    }
}

public class BatchUploadRequest
{
    public List<IFormFile> Files { get; set; }
    public string FileType { get; set; }
}